<?phprequire_once("../Entidade/Cliente.php");require_once("../Includes/Funcoes.php");class ControleCliente {    function inserir($dados) {        $objCliente = new Cliente;        $nome = removeAcentos($dados['nome']);        $objCliente->set('nome', $nome);        $objCliente->set('logradouro', $dados['logradouro']);        $objCliente->set('numero', $dados['numero']);        $objCliente->set('bairro', $dados['bairro']);        $objCliente->set('cidade', $dados['cidade']);        $objCliente->set('estado', $dados['estado']);        $objCliente->set('cep', $dados['cep']);        $objCliente->set('telefone', $dados['telefone']);        $objCliente->set('celular', $dados['celular']);        $objCliente->set('cpf', $dados['cpf']);        $objCliente->set('email', $dados['email']);        $novaDat = explode('/', $dados['datNascimento']);        $novaData = $novaDat[2] . $novaDat[1] . $novaDat[0];        $objCliente->set('datNascimento', $novaData);        $objCliente->set('sexo', $dados['sexo']);        $objCliente->set('profissao', $dados['profissao']);        $objCliente->set('identidade', $dados['identidade']);        $objCliente->set('obs', $dados['obs']);        $objCliente->set('usuario', $dados['usuario']);        $objCliente->set('senha', $dados['senha']);                return $retorno = $objCliente->inserir();    }    function alterar($dados) {        $novaDat = explode('/', $dados['datNascimento']);        $novaData = $novaDat[2] . $novaDat[1] . $novaDat[0];        $objCliente = new Cliente;        $nome = removeAcentos($dados['nome']);        $objCliente->set('nome', $nome);        $objCliente->set('codCliente', $dados['codCliente']);        $objCliente->set('nome', $dados['nome']);        $objCliente->set('logradouro', $dados['logradouro']);        $objCliente->set('numero', $dados['numero']);        $objCliente->set('bairro', $dados['bairro']);        $objCliente->set('cidade', $dados['cidade']);        $objCliente->set('estado', $dados['estado']);        $objCliente->set('cep', $dados['cep']);        $objCliente->set('telefone', $dados['telefone']);        $objCliente->set('celular', $dados['celular']);        $objCliente->set('cpf', $dados['cpf']);        $objCliente->set('email', $dados['email']);        $objCliente->set('datNascimento', $novaData);        $objCliente->set('sexo', $dados['sexo']);        $objCliente->set('profissao', $dados['profissao']);        $objCliente->set('identidade', $dados['identidade']);        $objCliente->set('obs', $dados['obs']);        $objCliente->set('usuario', $dados['usuario']);        $objCliente->set('senha', $dados['senha']);        return $retorno = $objCliente->alterar();    }    function excluir($dados) {        $objCliente = new Cliente;        $objCliente->set('codCliente', $dados['codCliente']);        return $retorno = $objCliente->excluir();    }    function buscarTodos() {        $objCliente = new Cliente;        return $retorno = $objCliente->buscarTodos();    }    function buscarWhere($campo, $operador, $valor, $ordenar, $extra) {        $objCliente = new Cliente;        return $retorno = $objCliente->buscarWhere($campo, $operador, $valor, $ordenar, $extra);    }    function buscarPorNome($nome) {        $objCliente = new Cliente;        return $retorno = $objCliente->buscarPorNome($nome);    }    function buscarPorId($codCliente) {        $objCliente = new Cliente;        $objCliente->set('codCliente', $codCliente);        return $retorno = $objCliente->buscarPorId();    }    function buscarData() {        $objCliente = new Cliente;        return $retorno = $objCliente->buscarData();    }    function selectClientes($codCliente) {        $objCliente = new Cliente;        return $retorno = $objCliente->selectClientes($codCliente);    }}?>